mapper.sql:
where j.deleted = 0

    and j.job_name like concat('%', #{query.jobName}, '%')


    and j.enterprise_id = #{query.enterpriseId}


    and exists (
        select 1
        from job_post_education_rel jer
        where jer.job_post_id = j.id
          and jer.education_code = #{query.educationRequirement}
    )


    and exists (
        select 1
        from job_post_education_rel jer
        where jer.job_post_id = j.id
          and jer.education_code in

              #{educationCode}

    )


    and exists (
        select 1
        from job_post_major_rel jmr
        where jmr.job_post_id = j.id
          and jmr.major_code in

              #{majorCode}

    )


    and exists (
        select 1
        from job_post_school_category_rel jscr
        where jscr.job_post_id = j.id
          and jscr.category_dict_item_id in

              #{schoolCategoryId}

    )


    and j.experience_requirement = #{query.experienceRequirement}


    and j.salary_range = #{query.salaryRange}


    and j.work_county_code = #{query.workCountyCode}


    and j.work_city_code = #{query.workCityCode}


    and j.work_province_code = #{query.workProvinceCode}

mapper.select:
select j.id, j.enterprise_id, e.enterprise_name, j.job_name, j.job_category, coalesce(dexp.dict_label, j.experience_requirement) as experience_requirement, coalesce(dsal.dict_label, j.salary_range) as salary_range, j.recruit_count, j.work_province_code, j.work_city_code, j.work_county_code, concat_ws('-', rp.region_name, rc.region_name, rct.region_name) as work_region_name, j.contact_person, j.contact_phone, j.job_description, j.publish_time, j.status from job_post j left join enterprise_info e on e.id = j.enterprise_id and e.deleted = 0 left join sys_dict_item dexp on dexp.dict_type = 'experience_requirement' and dexp.dict_value = j.experience_requirement and dexp.enabled = 1 left join sys_dict_item dsal on dsal.dict_type = 'salary_range' and dsal.dict_value = j.salary_range and dsal.enabled = 1 left join sys_region rp on rp.region_code = j.work_province_code left join sys_region rc on rc.region_code = j.work_city_code left join sys_region rct on rct.region_code = j.work_county_code
order by j.id desc
limit #{query.offset}, #{query.safePageSize}

mapper.update:
update job_post
set deleted = 1,
    update_by = #{updateBy}
where id = #{id}
  and deleted = 0

update job_post
set deleted = 1,
    update_by = #{updateBy}
where deleted = 0
  and id in

    #{id}
